package main

import (
    "fmt"
    "log"
    "net/http"
    "regexp"
    "strings"
)

// Compliant: Sanitize user input before logging
func sanitizeForLog(input string) string {
    // Remove or escape newlines and carriage returns
    input = strings.ReplaceAll(input, "\n", "\\n")
    input = strings.ReplaceAll(input, "\r", "\\r")
    input = strings.ReplaceAll(input, "\t", "\\t")

    // Remove non-printable characters
    reg := regexp.MustCompile("[^\x20-\x7E]")
    input = reg.ReplaceAllString(input, "?")

    // Limit length to prevent log flooding
    if len(input) > 100 {
        input = input[:100] + "..."
    }

    return input
}

func handleLoginSecure(w http.ResponseWriter, r *http.Request) {
    username := r.FormValue("username")
    password := r.FormValue("password")

    // Safe: Sanitize before logging
    safeUsername := sanitizeForLog(username)
    log.Printf("Login attempt for user: %s", safeUsername)

    if !authenticate(username, password) {
        log.Printf("Failed login for user: %s", safeUsername)
        http.Error(w, "Invalid credentials", http.StatusUnauthorized)
        return
    }
    log.Printf("Successful login for user: %s", safeUsername)
}

// Compliant: Use structured logging
func processRequestSecure(userInput string) {
    err := validateInput(userInput)
    if err != nil {
        // Log with structured fields instead of interpolating user input
        log.Printf("Validation failed for input (length=%d): %v", len(userInput), err)
    }
}
